let angleX = 0;
let angleY = 0;
let angleZ = 0;
let colors;
let drag = false;
let prevX, prevY;
let points = [];
let nPoints = 21
let faces = [];
let faceColors = [];
let edgeColors = [];
let zoom = 0;
let animStartTime;
let animDuration = 10000; // in milliseconds
let captureAt = 127;


function setup() {
  createCanvas(1280, 1280, WEBGL);
  colors = ['#CECECE', '#FFDC5F', '#F59097', '#EB6134', '#1D8EBF', '#07BB7E', '#ECECEC'];

  for (let i = 0; i < nPoints; i++) {
    points.push(createVector(pseudorandom(-windowWidth/4, windowWidth/4), random(-windowHeight/3, windowHeight/3), random(-windowHeight/3.5, windowHeight/3.5)));
  }

  for (let i = 0; i < points.length; i++) {
    let face = [];
    let nVertices = int(pseudorandom(3, 7));
    for (let j = 0; j < nVertices; j++) {
      let index = floor(pseudorandom(points.length));
      face.push(points[index]);
    }
    faces.push(face);
    faceColors.push(pseudorandomPick(colors));
    edgeColors.push(pseudorandomPick(colors));
  }

  let bgCol = pseudorandomPick(colors);
  bgCol = color(red(bgCol) * 0.3, green(bgCol) * 0.3, blue(bgCol) * 0.3);
  background(bgCol);
  noLoop();
  animStartTime = millis();
  loop();
}

function draw() {
  let t = (millis() - animStartTime) / animDuration;
  if (t > 1) {
    animStartTime = millis();
    t = 0;
  }

  zoom = map(sin(PI * t), -128, 128, -1460, 1840);

  angleX += PI * 3.14 * t / 240;
  angleY += PI * 3.14 * t / 1024;
  angleZ += PI * 3.14 * t / 38;

  rotateX(angleX);
  rotateY(angleY);
  rotateZ(angleZ);

  translate(0, 0, zoom);

  if (drag) {
    angleX += (mouseX - prevX) * 0.005;
    angleY -= (mouseY - prevY) * 0.005;
  }

  prevX = mouseX;
  prevY = mouseY;

  rotateX(angleY);
  rotateY(angleX);

  strokeWeight(2);

  for (let i = 0; i < faces.length; i++) {
    let face = faces[i];
    fill(faceColors[i]);
    stroke(edgeColors[i]);

    beginShape();
    for (let pt of face) {
      vertex(pt.x, pt.y, pt.z);
    }
    endShape(CLOSE);
  }
  if (frameCount === captureAt) capture();
}

function mousePressed() {
  drag = true;
  loop();
}

function mouseReleased() {
  drag = false;
  noLoop();
}

function mouseWheel(event) {
  zoom += event.delta * -0.1;
}
